INSERT INTO changelog_entries (version, title, description, changes, release_date, category, is_published) VALUES
('2.16.0', 'LinkedIn & SlideShare Deep Integration', 'Full-spectrum LinkedIn sharing pipeline with article generation, interactive presentations, and social post formatting for cases, timelines, entities, and analyses.', '["LinkedIn Share Menu with one-click post sharing, article generation, and presentation export", "Interactive HTML slide deck generator with keyboard navigation, fullscreen mode, and print-to-PDF for SlideShare", "LinkedIn Article Generator transforming case data into formatted markdown with executive summaries, stats tables, and entity breakdowns", "Social post formatter with auto-hashtags and engagement-optimized text", "Integrated across Case Profiles, Entity Details, Event Details, and Violation pages", "Presentation slides include cover, stats, timeline, entities, findings, and CTA slides"]', '2026-03-05', 'major', true),
('2.15.0', 'Featured Case Pinning & PDF Report Redesign', 'Case library now pins featured cases to the top, and the PDF export system received a complete visual overhaul matching court-grade standards.', '["Featured cases automatically pinned to top of Case Library with priority sorting", "Redesigned PDF cover page with centered HRPM logo, blue accent divider, and dark metadata band", "PDF metadata band displays generation time, severity level, and lead investigator", "Case title promoted to primary heading with Official Case Intelligence Report subtitle", "Print-optimized layout with proper page breaks and professional formatting"]', '2026-03-04', 'major', true),
('2.14.0', 'Legal Intelligence & Regulatory Harm Analysis', 'Comprehensive legal research toolkit with statute browsing, doctrine mapping, case law panels, and regulatory harm tracking with financial impact assessment.', '["Statute Browser with jurisdiction-filtered legal code lookup and section cross-referencing", "Doctrine Mapper linking legal doctrines to active cases with application notes", "Case Law Panel with precedent search, landmark case filtering, and citation verification", "Appeal Summary Generator producing AI-powered appellate briefs from case data", "Regulatory Harm Tab with incident tracking, financial loss quantification, and affidavit uploads", "Compliance violation detection with SOP comparison tables and procedural failure timelines", "International violations analysis with framework breakdowns across UDHR, ICCPR, ICESCR, and CAT"]', '2026-03-02', 'major', true);
